#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""Discover the email-scaler / ICP-ranker / deepcrawl units, RESTART them to fire a
run now that PG slots are free, and publish their names+states. exit-0-safe, read-mostly
(only systemctl restart of bounded background jobs)."""
import os,sys,json,time,subprocess,base64,urllib.request,urllib.error
def sh(c,t=20):
    try:
        r=subprocess.run(["bash","-lc",c],capture_output=True,text=True,timeout=t); return (r.stdout+r.stderr).strip()
    except Exception as e: return "ERR:%s"%e
out={"kind":"units_kick","ts":int(time.time())}
try:
    pat='deepcrawl|icp|email|scaler|rank|enrich_async|coverage'
    out["units"]=sh("systemctl list-units --all --plain --no-legend 'atlas*' 2>/dev/null | grep -iE '%s' | awk '{print $1\" \"$3\"/\"$4}'"%pat)
    out["timers"]=sh("systemctl list-timers --all --no-legend 2>/dev/null | grep -iE '%s' | awk '{print $5\" \"$NF}'"%pat)
    # discover service unit names to kick
    svcs=sh("systemctl list-unit-files --no-legend 2>/dev/null | grep -iE '(%s)' | grep -E '\\.service' | awk '{print $1}' | grep -vE 'enrich-pool' | head -12"%pat)
    out["discovered_services"]=svcs
    kicked=[]
    for u in svcs.split():
        if not u.endswith(".service"): continue
        if "enrich-pool" in u: continue
        r=sh("systemctl restart %s 2>&1; echo rc=$?"%u, t=30)
        kicked.append({"unit":u,"restart":r[-40:]})
    out["kicked"]=kicked
    time.sleep(8)
    out["post_state"]=sh("for u in $(systemctl list-unit-files --no-legend 2>/dev/null | grep -iE '(%s)' | grep -E '\\.service' | grep -vE 'enrich-pool' | awk '{print $1}' | head -12); do echo \"$u=$(systemctl is-active $u 2>/dev/null)\"; done"%pat)
except Exception as e:
    out["error"]=str(e)
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#'):
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
try:
    env=envf("/etc/atlas/autopull.env")
    tok=env.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN")
    repo=env.get("STATUS_REPO") or "cloudwalker171/atlas-manifests"
    br=env.get("STATUS_BRANCH","main"); api="https://api.github.com"; path="status/hetzner/units_kick.json"
    if tok and repo:
        url="%s/repos/%s/contents/%s"%(api,repo,path); sha=None
        try:
            r=urllib.request.Request(url+"?ref="+br,headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"})
            sha=json.load(urllib.request.urlopen(r,timeout=20)).get("sha")
        except Exception: sha=None
        body={"message":"units_kick","content":base64.b64encode(json.dumps(out,indent=2,default=str).encode()).decode(),"branch":br}
        if sha: body["sha"]=sha
        for _ in range(4):
            try:
                rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas","Content-Type":"application/json"})
                urllib.request.urlopen(rq,timeout=25); break
            except urllib.error.HTTPError as e:
                if e.code==409:
                    try:
                        rq2=urllib.request.Request(url+"?ref="+br,headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"})
                        body["sha"]=json.load(urllib.request.urlopen(rq2,timeout=20)).get("sha")
                    except Exception: pass
                else: break
            except Exception: time.sleep(2)
except Exception: pass
sys.exit(0)
